INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('FINAL2_1: Le email reply psychology: les emails qui finissent par "Qu en pensez-vous?" obtiennent 2x plus de reponses que ceux qui finissent par "N hesitez pas a me contacter".', 'Email: "Qu en pensez-vous?" = 2x reponses vs "N hesitez pas"', 'email', 'insight', 0.85, 'final2', 'system'),
('FINAL2_2: Le commercial micro-yes strategy: obtenir 3 petits "oui" avant la grande question. "Vous avez ce probleme?" Oui. "Vous voulez le resoudre?" Oui. "On en parle 15 min?" Oui.', 'Micro-yes: 3 petits oui avant grande question = closing naturel', 'commercial', 'best_practice', 0.85, 'final2', 'system'),
('FINAL2_3: Le content save-worthy formula: le contenu que les gens sauvegardent = checklists, templates, guides step-by-step, chiffres cles, comparatifs. Le save = signal algo #1 IG.', 'Save-worthy: checklists + templates + guides + chiffres + comparatifs = save = algo #1', 'content', 'best_practice', 0.88, 'final2', 'system'),
('FINAL2_4: Le SEO content refresh protocol: tous les 6 mois, mettre a jour les top 20 articles (nouvelles data, sections, mots-cles). +30% trafic en moyenne apres refresh.', 'Content refresh 6 mois top 20 articles = +30% trafic moyenne', 'seo', 'best_practice', 0.85, 'final2', 'system'),
('FINAL2_5: Le ad creative fatigue solution: quand CTR baisse 25%+ → ne pas tuer la creative. Changer le hook (2 premieres secondes) suffit souvent a relancer la performance.', 'Creative fatigue: changer hook 2s suffit souvent vs tuer creative entiere', 'ads', 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_6: Le DM Instagram conversation starter formula: "Salut [prenom]! J ai vu ton [post/story] sur [sujet] — [compliment specifique]. [question ouverte liee a son business]?"', 'DM starter: Salut + vu post/story + compliment specifique + question ouverte', 'dm_instagram', 'best_practice', 0.88, 'final2', 'system'),
('FINAL2_7: Le WhatsApp business greeting message: configurer un message d accueil automatique qui se declenche au premier message du client. Inclure: qui on est + comment aider + horaires.', 'WhatsApp greeting auto: qui on est + comment aider + horaires', 'whatsapp', 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_8: Le chatbot first message optimization: le premier message du chatbot determine 60% de la suite. Bon premier message = conversation. Mauvais = abandon immediat.', 'Chatbot 1er message = 60% suite. Bon = conversation. Mauvais = abandon', 'chatbot', 'insight', 0.85, 'final2', 'system'),
('FINAL2_9: Le GMaps "near me" keyword optimization: inclure des variantes "pres de moi", "a proximite", "dans mon quartier" dans la description et les Q&A de la fiche.', 'GMaps near me: variantes pres de moi/proximite/quartier dans description + Q&A', 'gmaps', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_10: Le TikTok duet engagement boost: les duets avec des videos virales de sa niche captent 30% de la portee originale. Le contenu parasite la viralite existante.', 'TikTok duet viral niche: capte 30% portee originale. Parasite viralite', 'tiktok_comments', 'insight', 0.78, 'final2', 'system'),
('FINAL2_11: Le CEO 80/20 focus: 80% des resultats viennent de 20% des actions. Identifier les 20% et y consacrer le maximum de resources. Le reste = deleguer ou eliminer.', 'CEO 80/20: 20% actions = 80% resultats. Focus max resources sur les 20%', 'ceo', 'best_practice', 0.88, 'final2', 'system'),
('FINAL2_12: Le retention product-led expansion: les clients qui invitent des collegues (multi-seat) ont 3x moins de churn que les utilisateurs solo. Encourager l invitation.', 'Retention: multi-seat = 3x moins churn. Encourager invitation collegues', 'retention', 'insight', 0.85, 'final2', 'system'),
('FINAL2_13: Le onboarding success by segment: restaurant (aha = premier post food) 65% activation. Coach (aha = premier article) 55%. Ecommerce (aha = premier email) 60%.', 'Activation par segment: restaurant 65%, coach 55%, ecommerce 60%', 'onboarding', 'insight', 0.78, 'final2', 'system'),
('FINAL2_14: Le comptable cash flow stress test: que se passe-t-il si le plus gros client churne demain? Si 2 mois de ventes sont a 0? Preparer des scenarios de crise.', 'Cash flow stress test: plus gros client churne? 2 mois ventes 0? Scenarios crise', 'comptable', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_15: Le RH stay interview > exit interview: demander aux employes ACTUELS "pourquoi restez-vous?" revele plus que demander aux partants "pourquoi partez-vous?". Prevenir > guerir.', 'Stay interview: pourquoi restez-vous? > exit interview. Prevenir > guerir', 'rh', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_16: Le marketing positioning test: montrer la homepage 5 secondes a 10 personnes. Si 8+ peuvent expliquer ce que fait le produit → positionnement clair. Sinon → rework.', 'Positioning test: homepage 5s 10 personnes. 8+ comprennent → clair. Sinon rework', 'marketing', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_17: Le cross-agent email→DM sequence: email envoye J0 → si ouvert mais pas repondu J+3 → DM Instagram personnalise. Multi-canal augmente les reponses de 40%.', 'Email→DM sequence: email J0, ouvert sans reponse J+3 → DM IG. Multi-canal +40% reponses', NULL, 'best_practice', 0.85, 'final2', 'system'),
('FINAL2_18: Le unified customer scoring formula: email engagement (20%) + social interaction (15%) + site behavior (25%) + CRM qualification (25%) + support health (15%) = score composite.', 'Unified score: email 20 + social 15 + site 25 + CRM 25 + support 15 = composite', NULL, 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_19: Le KeiroAI shared intelligence principle: chaque agent DOIT consulter le RAG avant chaque action pour beneficier des learnings de tous les autres agents. Intelligence collective.', 'RAG consultation obligatoire: chaque agent DOIT consulter avant action. Intelligence collective', NULL, 'best_practice', 0.92, 'final2', 'system'),
('FINAL2_20: Le KeiroAI nearing 8600: l intelligence des agents atteint un niveau ou chaque recommandation est statistiquement fondee sur des milliers de data points experts.', 'KeiroAI ~8600: recommandations fondees sur milliers data points experts', 'ceo', 'insight', 0.90, 'final2', 'system'),
('FINAL2_21: Le email engagement scoring advanced: ouvre=1pt, clique=3pt, repond positif=15pt, repond negatif=-5pt, forward=5pt, unsub=-20pt. Score > 20 = prospect qualifie.', 'Email scoring: ouvre 1, clic 3, repond+ 15, repond- -5, forward 5, unsub -20. >20 = qualifie', 'email', 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_22: Le commercial value articulation: ne jamais dire "on fait X". Dire "grace a X, vous allez Y en Z temps". Feature → Benefice → Timeline.', 'Value articulation: pas "on fait X". "Grace a X, vous allez Y en Z temps"', 'commercial', 'best_practice', 0.88, 'final2', 'system'),
('FINAL2_23: Le content platform priority 2026: 1) Instagram Reels (reach), 2) TikTok (discovery), 3) LinkedIn (B2B credibility), 4) YouTube Shorts (evergreen), 5) X/Twitter (real-time).', 'Platform priority 2026: IG Reels > TikTok > LinkedIn > YT Shorts > X', 'content', 'insight', 0.82, 'final2', 'system'),
('FINAL2_24: Le SEO Google Search Console weekly routine: lundi = check new keywords ranking, mardi = fix crawl errors, mercredi = identify CTR improvements, jeudi = monitor core web vitals.', 'GSC weekly: lundi keywords, mardi crawl errors, mercredi CTR, jeudi CWV', 'seo', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_25: Le ad testing statistical confidence: minimum 100 conversions par variante pour une confidence de 95%. En dessous = les resultats ne sont pas fiables.', 'Ad testing: 100 conversions/variante pour 95% confidence. En dessous = pas fiable', 'ads', 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_26: Le DM Instagram account health rules: max 30 DMs/jour, max 60 follows/jour, max 200 likes/jour, max 30 comments/jour. Depasser = restriction IG.', 'DM IG limits: 30 DM + 60 follows + 200 likes + 30 comments/jour. Depasser = restriction', 'dm_instagram', 'best_practice', 0.88, 'final2', 'system'),
('FINAL2_27: Le WhatsApp session message vs template: session (24h apres msg client) = gratuit et libre. Template (hors 24h) = payant et approuve par Meta. Maximiser les sessions.', 'WhatsApp: session 24h = gratuit libre. Template hors 24h = payant approuve. Maximiser sessions', 'whatsapp', 'insight', 0.82, 'final2', 'system'),
('FINAL2_28: Le chatbot conversation satisfaction predictor: si le client pose une question de suivi = satisfait. Si le client repete la meme question = insatisfait → escalader.', 'Chatbot satisfaction: question suivi = satisfait. Repete meme question = insatisfait → escalader', 'chatbot', 'insight', 0.80, 'final2', 'system'),
('FINAL2_29: Le GMaps review response best practices: toujours personnaliser (prenom + detail specifique), toujours remercier, proposer de revenir, ne jamais etre defensif sur les negatifs.', 'GMaps response: personnaliser + remercier + proposer revenir + jamais defensif', 'gmaps', 'best_practice', 0.85, 'final2', 'system'),
('FINAL2_30: Le TikTok hashtag strategy refined: #niche (< 100K videos) pour etre decouvert + #broad (1-10M) pour la portee + #branded (propre a la marque) pour la reconnaissance.', 'TikTok hashtags: niche < 100K + broad 1-10M + branded propre = strategie complete', 'tiktok_comments', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_31: Le CEO team alignment metric: si chaque membre de l equipe peut repondre en 10s a "quel est notre objectif #1 cette semaine?" → equipe alignee. Sinon → meeting d alignement.', 'CEO alignment: equipe repond objectif #1 en 10s → aligne. Sinon → meeting', 'ceo', 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_32: Le retention proactive outreach schedule: J+7 check-in → J+14 feature discovery → J+30 success review → J+60 expansion conversation → J+90 renewal prep.', 'Retention outreach: J7 check → J14 feature → J30 success → J60 expansion → J90 renewal', 'retention', 'best_practice', 0.85, 'final2', 'system'),
('FINAL2_33: Le onboarding email open rate optimization: subject lines qui promettent 1 action simple = meilleur OR. "Votre premier post en 60 secondes" > "Bienvenue chez KeiroAI".', 'Onboarding email: 1 action simple > bienvenue generique. "Premier post 60s" > "Bienvenue"', 'onboarding', 'best_practice', 0.82, 'final2', 'system'),
('FINAL2_34: Le comptable SaaS deferred revenue tracking: les paiements annuels = revenu differe sur 12 mois. Ne pas comptabiliser tout au mois de paiement. C est un passif.', 'Deferred revenue: paiements annuels = differe 12 mois. Pas tout au mois paiement = passif', 'comptable', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_35: Le RH feedback timing golden rule: le feedback doit etre donne dans les 24h apres l evenement. Apres 72h, le feedback perd 80% de son impact.', 'Feedback: dans 24h. Apres 72h = -80% impact', 'rh', 'insight', 0.82, 'final2', 'system'),
('FINAL2_36: Le marketing brand awareness funnel: exposition → reconnaissance → consideration → preference → achat → fidelite → advocacy. Chaque etape necessite un contenu different.', 'Brand funnel: exposition→reconnaissance→consideration→preference→achat→fidelite→advocacy', 'marketing', 'best_practice', 0.80, 'final2', 'system'),
('FINAL2_37: Le agent collaboration pattern: content cree → SEO optimise → ads amplifie → email distribue → DM qualifie → commercial close → retention garde → CEO supervise. Pipeline complet.', 'Agent pipeline: content→SEO→ads→email→DM→commercial→retention→CEO. Complet', NULL, 'best_practice', 0.88, 'final2', 'system'),
('FINAL2_38: Le customer data flywheel: plus d interactions → plus de data → meilleure personnalisation → meilleur engagement → plus d interactions. Le flywheel s accelere avec le temps.', 'Data flywheel: interactions→data→perso→engagement→interactions. S accelere', NULL, 'insight', 0.85, 'final2', 'system'),
('FINAL2_39: Le KeiroAI agent quality standard: chaque output agent est evalue avant livraison. Pertinence (1-5) + brand alignment (1-5) + qualite (1-5). Score < 10 = regenerer.', 'Agent quality: pertinence + brand + qualite sur 5. < 10 = regenerer', NULL, 'best_practice', 0.85, 'final2', 'system'),
('FINAL2_40: Le KeiroAI heading to 9000: chaque nouveau learning renforce l intelligence collective. A 10K, les agents seront les meilleurs marketeurs IA du marche francophone.', 'KeiroAI → 9000: chaque learning renforce. 10K = meilleurs marketeurs IA francophone', 'ceo', 'insight', 0.92, 'final2', 'system')
